function calculateExpression(expression: string): number {
  let result = 0;
  let operator = '+';
  let num = 0;
  for (let i = 0; i < expression.length; i++) {
    const char = expression[i];
    if (char === '0' || char === '1' || char === '2' || char === '3' || char === '4' || char === '5' || char === '6' || char === '7' || char === '8' || char === '9') {
      num = num * 10 + parseInt(char);
    } else if (char === '+' || char === '-' || char === '*' || char === '/') {
      result = calculateOperator(result, operator, num);
      num = 0;
      operator = char;
    }
  }
  return calculateOperator(result, operator, num);
}

function calculateOperator(a: number, operator: string, b: number): number {
  if (operator === '+') {
    return a + b;
  } else if (operator === '-') {
    return a - b;
  } else if (operator === '*') {
    return a * b;
  } else if (operator === '/') {
    return a / b;
  }
}

