  def calculateExpression(self, expression: str) -> int:
    result = 0
    operator = '+'
    num = 0
    for char in expression:
      if char.isdigit():
        num = num * 10 + int(char)
      elif char in ['+', '-', '*', '/']:
        result = self.calculateOperator(result, operator, num)
        num = 0
        operator = char
    return self.calculateOperator(result, operator, num)

  def calculateOperator(self, a: int, operator: str, b: int) -> int:
    if operator == '+':
      return a + b
    elif operator == '-':
      return a - b
    elif operator == '*':
      return a * b
    elif operator == '/':
      return a // b

